#include <bits/stdc++.h>
using namespace std;
int n,s[402],f[402],dp[3][800005],ans;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&s[i],&f[i]);
    memset(dp,-999999,sizeof(dp));
    dp[1][400000]=dp[2][400000]=0;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=800000;j++){
            if(j>s[i])
                dp[2][j]=max(dp[1][j],dp[1][j-s[i]]+f[i]);
            else
            	dp[2][j]=dp[1][j];
        }
        for(int j=1;j<=800000;j++)
            dp[1][j]=dp[2][j];
    }
    for(int i=400000;i<=800000;i++) 
        if(dp[1][i]>=0)
            ans=max(ans,dp[1][i]+i-400000);
    printf("%d",ans);
    return 0;
}
